export const meta = {
  name: 'plan-mode-planning-agent',
  description: 'Build plan-mode planning agent (council of subagents + ground-truth .md) in packages/tui',
  phases: [
    { title: 'Session module' },
    { title: 'Council module' },
    { title: 'Runtime wiring' },
    { title: 'TUI wiring' },
    { title: 'Tests' },
    { title: 'Verify' },
    { title: 'Review' },
  ],
}

const ROOT = '/Users/ammarnagri/Documents/mubit-ai/minima/packages/tui'

const COMMON = `
Repo: ${ROOT}  (a Bun + TypeScript + Ink harness; NOT Python — do not add \`from __future__\`, Pydantic, etc.)
Toolchain: \`cd ${ROOT} && bun run check\` (tsc --noEmit), \`bun run lint\` (biome), \`bun test\` (hermetic).
Conventions to MATCH the surrounding code:
- No comments unless they clarify something non-obvious; match the terse style of existing files (see src/minima/budget.ts, runtime.ts).
- camelCase for TS identifiers/interfaces; snake_case ONLY for wire DTO fields (not relevant to these new files).
- Bookkeeping / telemetry must be FAIL-OPEN: wrap in try/catch and never throw out of the hot path.
- biome line width is 100; keep imports with explicit \`.ts\` extensions like the rest of the repo.
- Reuse existing machinery, do NOT reinvent it.
Key existing pieces you will reuse (read them):
- src/tools/task.ts: \`Delegation\`, \`ChildResult\`, \`SpawnFn\`, \`executeDag(ds, spawn, {depth, signal, concurrency})\`.
- src/minima/spawn.ts: \`createSpawn({parent, workdir, onChildEvent})\` -> SpawnFn; \`ChildEvent\`. Children are child MinimaAgents; a child's tools = builtinTools({workdir, exclude:["task"]}) filtered by delegation.tool_allowlist. IMPORTANT: children do NOT inherit the lead's read-only plan-mode block, so researcher delegations MUST set tool_allowlist to read-only tools: ["read","ls","glob","grep","web_search","web_fetch"] and boundaries that say read-only.
- src/ai/stream.ts: \`complete(model, context, {options, signal})\` -> Promise<AssistantMessage>. Build context with \`{ system_prompt, messages: [new Message({role:"user", content})], tools: [] }\` (see src/ai/types.ts: Message, Context, text(), Model, AssistantMessage.textContent, AssistantMessage.usage.cost.total).
- src/minima/judge.ts: LLMJudge shows the pattern — JUDGE_SYSTEM prompt-injection hardening (wrap untrusted text in <response>/<approach> delimiters and tell the model never to obey instructions inside them), midTruncate for input caps, defensive parsing that returns a safe fallback instead of throwing.
- src/minima/runtime.ts: MinimaAgent — \`agent.router\`, \`agent.mapping\`, \`agent.config.judgeModel\`, \`agent.promptRouted(text, {difficulty})\`, \`agent.agentState.systemPrompt\`, \`agent.agentState.messages\`.
- src/ai/registry.ts: \`findModelById(id)\`. src/minima/mapping.ts: \`ModelMapping.defaultModel()\`.
- src/db/minima_db.ts: \`newId()\` (crypto.randomUUID).
`

// The pinned cross-module contract — every stage builds against exactly these shapes.
const CONTRACT = `
=== PINNED INTERFACE CONTRACT (implement EXACTLY these exported shapes) ===

// ---- src/minima/plan_session.ts (pure; only imports newId from ../db/minima_db.ts) ----
export interface PlanDecision { id: string; topic: string; decision: string; rationale: string; resolvedBy: "council" | "user"; round: number; }
export interface OpenQuestion { id: string; question: string; why: string; round: number; status: "open" | "answered" | "dropped"; answer?: string; }
export interface CouncilFinding { id: string; source: "researcher" | "critic" | "keeper"; summary: string; severity: "info" | "concern" | "blocker"; round: number; }
export interface PlanConstraint { id: string; text: string; source: "user" | "council"; }
export interface PlanFact { id: string; text: string; round: number; }
export interface SurfacedQuestion { question: string; header: string; options: { label: string; description?: string }[]; why: string; }
export interface CouncilRoundResult {
  draftDelta: string;
  decisions: { topic: string; decision: string; rationale: string }[];
  findings: { source: "researcher" | "critic" | "keeper"; summary: string; severity: "info" | "concern" | "blocker" }[];
  faults: { summary: string; severity: "info" | "concern" | "blocker" }[];
  questions: SurfacedQuestion[];
  facts: string[];
  constraints: string[];
  costUsd: number;
  aborted: boolean;
}
export interface PlanSession {
  goal: string; draft: string;
  decisions: PlanDecision[]; openQuestions: OpenQuestion[];
  findings: CouncilFinding[]; constraints: PlanConstraint[]; facts: PlanFact[];
  rounds: number; totalCouncilCostUsd: number; createdAt: number; updatedAt: number;
}
export class PlanSessionStore {
  constructor(goal: string);
  get session(): PlanSession;
  setGoal(goal: string): void;
  applyCouncilResult(r: CouncilRoundResult): void;   // merge+dedup by normalized topic/question/summary; bump rounds and totalCouncilCostUsd; MUST be fail-open (never throw)
  recordUserTurn(text: string): void;                // append a PlanFact
  answerQuestion(question: string, answer: string): void; // mark matching OpenQuestion answered; add a resolvedBy:"user" PlanDecision
  addSurfacedQuestions(qs: SurfacedQuestion[], round: number): void; // append as status:"open" OpenQuestions (dedup)
  snapshotBlock(): string;   // compact re-anchor projection: goal, resolved decisions, hard constraints, still-open questions, current draft
  toMarkdown(): string;      // the ground-truth doc (see format below)
  summary(): string;         // one-line status
  hasSubstance(): boolean;   // decisions.length>0 || draft.trim().length>0
}
export function buildPlannerSystemPrompt(base: string, store: PlanSessionStore): string; // base persona + store.snapshotBlock()

// ---- src/minima/plan_council.ts ----
export interface CouncilEvent { phase: "scope" | "research" | "keeper" | "critic" | "synth" | "done"; note: string; }
export interface CouncilOptions {
  parent: MinimaAgent;            // from ../minima/runtime.ts (import type)
  metaModel: Model;              // fixed cheap model for keeper/critic/synth complete() calls
  signal?: AbortSignal | null;
  workdir?: string;              // default process.cwd()
  maxResearchers?: number;       // default 3
  concurrency?: number;          // default 3
  maxCriticPasses?: number;      // default 3
  roundBudgetUsd?: number;       // soft cap; stop launching researchers once exceeded
  apiKey?: string;
  spawn?: SpawnFn;               // injectable for tests; DEFAULT = createSpawn({parent, workdir, onChildEvent})
  onEvent?: (e: CouncilEvent) => void;
  onChildEvent?: (e: ChildEvent) => void;
}
export class Critic {
  constructor(model: Model, opts?: { apiKey?: string; timeout?: number });
  attack(goal: string, approach: string, findings: string, signal?: AbortSignal | null): Promise<{ summary: string; severity: "info" | "concern" | "blocker" }[]>;
}
export function shouldConveneCouncil(userTurn: string): boolean; // adaptive cadence: return false for short acknowledgements/confirmations (e.g. <=~6 words, "yes"/"ok"/"do that"/"option b"), true for substantive turns
export function runCouncilRound(session: PlanSession, userTurn: string, opts: CouncilOptions): Promise<CouncilRoundResult>;
=== END CONTRACT ===

GROUND-TRUTH .md FORMAT (PlanSessionStore.toMarkdown): a single doc titled "# Ground Truth: <goal>" with a generated-by subtitle (N rounds, $cost), then sections: ## Goal, ## Constraints (bullet list), ## Key Decisions (### <topic> with **Decision:** / **Rationale:** / provenance "resolved by <who>, round N"), ## Plan (the draft prose), ## Open Questions (unresolved ones, flagged), ## Context & Findings (bulleted, tagged by source). Deterministic string assembly — no LLM call.
`

const DESIGN = `
BEHAVIORAL DESIGN (user-confirmed):
- Adaptive cadence: shouldConveneCouncil() decides whether a plan turn convenes the council.
- Standard depth: <=3 parallel read-only researchers + a keeper + 1 critic + a synth stage.
- Critic self-improve loop: inside runCouncilRound, after research, loop up to maxCriticPasses (default 3): critic.attack the current draftDelta; if it returns faults, do ONE meta "reviser" complete() call that revises the draftDelta to address them; re-attack; stop when no faults or the cap is hit. Then a synth complete() call turns findings+faults+userTurn into the CouncilRoundResult, RESOLVING trivial/self-answerable questions itself (as decisions/facts) and SURFACING only genuine decision-points as questions[] (cap ~2 per round).
- Council pipeline: (1) keeper deriveScopes = one complete() call -> up to maxResearchers non-overlapping {focus, boundaries, output_format, difficulty}; fallback to a single scope from userTurn if the call fails/parses empty. (2) research = build Delegation[] (focus->objective, boundaries verbatim, output_format, difficulty, effort:"light", tool_allowlist:["read","ls","glob","grep","web_search","web_fetch"], a small budget_usd slice) then executeDag(delegations, spawn, {depth:1, signal, concurrency}). (3) optional keeper post-check complete() flags off-scope findings (down-weight, don't discard). (4) critic self-improve loop. (5) synth.
- Meta calls (deriveScopes, keeper post-check, reviser, synth) and the Critic use complete() on the FIXED metaModel — they are deliberately OFF the routing/feedback loop (like LLMJudge), so they never corrupt routing propensities. Only researchers route (they go through child.promptRouted inside createSpawn). Do NOT re-rank or override any RoutingResult.
- Every meta complete() call must parse defensively (helper like completeJson that extracts the first JSON object/array and returns a safe fallback on any error) and pass through the abort signal.
- Cost: sum researcher ChildResult.costUsd into CouncilRoundResult.costUsd; respect roundBudgetUsd as a soft cap (stop launching researchers past it). On abort, return partial result with aborted:true.
`

phase('Session module')
const sessionRes = await agent(
  `${COMMON}\n${CONTRACT}\n
Create the file src/minima/plan_session.ts implementing EXACTLY the plan_session.ts portion of the contract. It is pure (no network, no LLM) — the single source of truth for the in-memory planning session and the ground-truth .md synthesis. Use newId() from ../db/minima_db.ts for ids and Date.now()/1000 for timestamps (mirror how src/minima/budget.ts stamps time). applyCouncilResult must dedup (normalize whitespace+lowercase when comparing topics/questions/summaries) and be fully fail-open. snapshotBlock() is the compact projection re-injected into the planner's system prompt each turn — keep it tight. toMarkdown() follows the GROUND-TRUTH .md FORMAT exactly, deterministic.
Also: add the plan_session exports to src/minima/index.ts (mirror the existing export style there — export the class, the functions, and \`export type {...}\` for the interfaces).
Do NOT touch any other file. Report exactly what you created/changed.`,
  { phase: 'Session module' },
)

phase('Council module')
const councilRes = await agent(
  `${COMMON}\n${CONTRACT}\n${DESIGN}\n
The file src/minima/plan_session.ts already exists (read it first to match its exact exported types). Create src/minima/plan_council.ts implementing EXACTLY the plan_council.ts portion of the contract, following the BEHAVIORAL DESIGN. Import types from ./plan_session.ts, ../minima/runtime.ts (MinimaAgent), ../ai/types.ts (Model, Message, text, AssistantMessage), ./spawn.ts (createSpawn, ChildEvent), ../tools/task.ts (Delegation, SpawnFn, executeDag), and complete from ../ai/stream.ts. Reuse the LLMJudge hardening pattern from ./judge.ts for the Critic and every meta prompt. Keep the module cohesive and testable: the internal stage helpers (deriveScopes, research, keeper post-check, the critic self-improve loop, synth, and a completeJson JSON-extraction helper) should be small named functions. shouldConveneCouncil is a cheap pure heuristic (no LLM).
Then add the plan_council exports to src/minima/index.ts alongside the plan_session ones (export runCouncilRound, Critic, shouldConveneCouncil, and \`export type {...}\` for CouncilOptions/CouncilEvent).
Do NOT modify plan_session.ts, app.tsx, main.ts, or tests. Report what you created/changed and the final exported signatures.`,
  { phase: 'Council module' },
)

phase('Runtime wiring')
const runtimeRes = await agent(
  `${COMMON}\n${CONTRACT}\n
Wire the new plan-mode machinery into src/cli/main.ts so the TUI can use it. Read src/cli/main.ts around lines 435-535 first. Changes:
1. The createSpawn({parent: agent, workdir: process.cwd(), onChildEvent: e => childEventRef.handler?.(e)}) factory is currently created INLINE inside the taskTool({...}) call (~line 442-452). Hoist it to a named const (e.g. \`const spawnFactory = createSpawn({...})\`) and pass \`spawn: spawnFactory\` into taskTool — behavior unchanged.
2. Resolve a fixed cheap meta model for the council: \`const planMetaModel = findModelById(agent.config.judgeModel) ?? agent.mapping.defaultModel();\` (import findModelById from ../ai/registry.ts if not already imported).
3. Pass two NEW props into the HarnessApp React.createElement (the interactive render() near line 526-535): \`planSpawn: spawnFactory\` and \`planMetaModel\`.
Only edit src/cli/main.ts. Do not change the headless/print paths' behavior. Keep it minimal. Verify with \`cd ${ROOT} && bun run check\` that main.ts still typechecks after your edit (the app.tsx prop types get added in the next step — if check complains ONLY about unknown props on HarnessApp, that is expected and fine; report it, do not try to fix app.tsx). Report your diff.`,
  { phase: 'Runtime wiring' },
)

phase('TUI wiring')
const tuiRes = await agent(
  `${COMMON}\n${CONTRACT}\n${DESIGN}\n
Wire plan mode into the Ink TUI src/tui/app.tsx. This is a large file (~2470 lines) — read the relevant regions before editing: AppProps interface (~59-72), COMMANDS table (~132-158), getLastAssistant (~121), childEventRef effect (~700-723), askUserRef effect (~731-740), planMode state (~743-749), beforeToolCall permission hook (~813-832), Esc/abort handler (~1001-1019), handleCommand \`case "plan":\` (~1454-1472), onSubmit non-slash path (~1959-1975). Also read src/tui/messages.tsx for the ChatMessage shape used by setMessages.
Implement:
1. AppProps: add \`planSpawn?: SpawnFn\` (import type from ../tools/task.ts) and \`planMetaModel?: Model\`.
2. State/refs: \`planSessionRef = useRef<PlanSessionStore | null>(null)\`, \`plannerBaseSystemPromptRef = useRef<string | null>(null)\`, \`councilControllerRef = useRef<AbortController | null>(null)\`, and state \`awaitingPlanApproval\`/\`setAwaitingPlanApproval\` + a ref holding the last finalized markdown draft. Import PlanSessionStore, buildPlannerSystemPrompt, runCouncilRound, Critic, shouldConveneCouncil from ../minima/index.ts (or the module files).
3. Expand \`case "plan":\` into a subcommand dispatcher on \`args.split(/\\s+/)[0]\` (mirror the /budget handler style ~1541-1603), supporting: no-arg/toggle (preserve today's read-only toggle AND, when turning ON, create a fresh PlanSessionStore + stash the current systemPrompt into plannerBaseSystemPromptRef + set a planner-persona systemPrompt); \`start [goal...]\` (enter plan mode + set goal); \`status\` (print store.summary() + cumulative council cost); \`finalize [path]\` (guard hasSubstance(); render store.toMarkdown() as a tool message; set awaitingPlanApproval + stash the markdown; tell the user to /plan approve or keep talking); \`approve\` (write the stashed markdown to <path or "GROUND_TRUTH.md"> at process.cwd() via \`await Bun.write(...)\` DIRECTLY — NOT through the agent tool loop, so the read-only plan-mode block does not apply — then print the path, clear the session, restore plannerBaseSystemPromptRef into agent.agentState.systemPrompt, and exit plan mode); \`cancel\` (discard session, restore base prompt, exit plan mode). Update the COMMANDS \`plan\` desc to mention the subcommands.
4. onSubmit: in the non-slash branch, when planModeRef.current is true AND planSessionRef.current exists AND planSpawn+planMetaModel props are present, route through a new \`async function runPlanTurn(text)\` INSTEAD OF the plain \`agent.promptRouted(expanded)\`. runPlanTurn must:
   a. clear awaitingPlanApproval; store.recordUserTurn(text);
   b. if shouldConveneCouncil(text): create an AbortController (store in councilControllerRef), call runCouncilRound(store.session, text, { parent: agent, metaModel: planMetaModel, spawn: planSpawn, signal: controller.signal, onEvent: e => <push a muted progress notice via setMessages>, onChildEvent: childEventRef.handler ?? undefined }); then store.applyCouncilResult(result); render a compact muted summary of result.faults/findings; for each result.questions call askUserRef.current(qp) (map SurfacedQuestion -> QuestionParams) and store.answerQuestion(...) with the returned answer (skip if askUserRef null or dismissed). Wrap the whole council call in try/catch — on failure, push a muted notice and continue (fail-open: fall back to just the planner turn).
   c. re-anchor: \`agent.agentState.systemPrompt = buildPlannerSystemPrompt(plannerBaseSystemPromptRef.current ?? "", store)\` then \`await agent.promptRouted(text)\` (the planner's conversational reply, now anchored). Keep the existing routing/warnings/feedback surfacing that the normal path already does, or factor it so both paths share it.
5. Esc handler (~1017): when aborting during plan mode, also call \`councilControllerRef.current?.abort()\` before/besides agent.abort().
Keep all heavy logic in the two ../minima modules — app.tsx should be thin wiring only. Preserve ALL existing behavior for non-plan-mode turns. After editing, run \`cd ${ROOT} && bun run check\` and fix any type errors you introduced (it should now find the props from the runtime-wiring step). Report your diff and the check result.`,
  { phase: 'TUI wiring', effort: 'high' },
)

phase('Tests')
const testResults = await parallel([
  () => agent(
    `${COMMON}\n${CONTRACT}\n
Write a hermetic bun test at tests/plan_session.test.ts for src/minima/plan_session.ts. Look at an existing test (e.g. tests/*.test.ts, and packages/tui/tests/web_search.test.ts) for the import/style conventions (\`import { test, expect } from "bun:test"\`). Pure tests, no provider needed. Cover: applyCouncilResult merges + dedups (same topic/question twice -> one entry) and bumps rounds/totalCouncilCostUsd; council-resolved decisions land in session.decisions while surfaced questions land in openQuestions; answerQuestion marks the question answered and adds a user decision; snapshotBlock includes goal + decisions + open questions; toMarkdown emits all required sections (Goal, Constraints, Key Decisions, Plan, Open Questions, Context & Findings) and flags unresolved open questions; hasSubstance() guards an empty finalize; applyCouncilResult is fail-open on a malformed result (never throws). Only create this one test file. Report what you covered.`,
    { phase: 'Tests', label: 'test:session' },
  ),
  () => agent(
    `${COMMON}\n${CONTRACT}\n${DESIGN}\n
Write a hermetic bun test at tests/plan_council.test.ts for src/minima/plan_council.ts. Read src/minima/plan_council.ts and an existing spawn/e2e test to reuse the hermetic setup: registerFauxProvider + a faux Model, an in-memory MinimaDb(":memory:"), a MinimaAgent built over a mock service, and a MOCK/injected SpawnFn passed via CouncilOptions.spawn so no real child agents run (return canned ChildResult objects). The faux provider is a FIFO response queue — script the deriveScopes / critic / reviser / synth complete() replies in order. Assert: runCouncilRound returns researcher findings + critic faults + a draftDelta; the critic self-improve loop revises when faults are returned then stops when clean (assert the reviser ran, and that it stops at maxCriticPasses); a trivial/self-answerable question is resolved (lands in result.decisions) while a genuine one is surfaced in result.questions; shouldConveneCouncil returns false for a short ack ("ok", "yes do that") and true for a substantive turn; costUsd sums the injected child costs; an aborted signal yields aborted:true with a partial result; Critic.attack returns [] (no throw) on an unparseable reply. Only create this one test file. If the exact hermetic wiring is unclear, read tests/ for the closest existing example and copy its harness. Report what you covered and any spots you had to stub.`,
    { phase: 'Tests', label: 'test:council' },
  ),
])

phase('Verify')
let verifyLog = ''
let green = false
for (let i = 0; i < 5 && !green; i++) {
  const v = await agent(
    `${COMMON}\n
Run the full hermetic check for the plan-mode feature and report results as structured output. Run, IN ORDER, from ${ROOT}:
  1. \`bun run check\`  (tsc --noEmit)
  2. \`bun run lint\`   (biome check src)
  3. \`bun test\`       (whole suite must stay green — do not break existing tests)
Report passed=true ONLY if all three succeed with no errors. If anything fails, put the concise failing output (file:line + message) in \`failures\` and a one-line \`summary\`. Do NOT edit any files in this step — only run and report.`,
    { phase: 'Verify', label: `verify#${i + 1}`, schema: {
      type: 'object',
      additionalProperties: false,
      properties: {
        passed: { type: 'boolean' },
        summary: { type: 'string' },
        failures: { type: 'string' },
      },
      required: ['passed', 'summary', 'failures'],
    } },
  )
  log(`verify#${i + 1}: ${v?.passed ? 'GREEN' : 'red'} — ${v?.summary ?? 'no result'}`)
  if (v?.passed) { green = true; break }
  verifyLog = v?.failures ?? 'unknown failures'
  await agent(
    `${COMMON}\n${CONTRACT}\n
The plan-mode feature currently fails \`bun run check\` / \`bun run lint\` / \`bun test\`. Fix the failures WITHOUT weakening the feature or the tests (do not delete assertions or \`// @ts-ignore\` your way out; fix the real cause). Touch only what's needed. The failing output:\n\n${verifyLog}\n\nAfter fixing, re-run the three commands yourself to confirm locally, then report what you changed.`,
    { phase: 'Verify', label: `fix#${i + 1}` },
  )
}

phase('Review')
const review = await agent(
  `${COMMON}\n${CONTRACT}\n${DESIGN}\n
Adversarially review the plan-mode feature diff for correctness and faithfulness to the design. Run \`cd ${ROOT} && git diff --stat\` and inspect the new/changed files: src/minima/plan_session.ts, src/minima/plan_council.ts, src/minima/index.ts, src/cli/main.ts, src/tui/app.tsx, tests/plan_session.test.ts, tests/plan_council.test.ts. Check specifically: (a) researchers are constrained read-only via tool_allowlist (no way for a council spawn to write during plan mode); (b) meta/critic/synth calls use the fixed metaModel via complete() and never route or re-rank RoutingResult (propensity integrity); (c) the finalize .md is written directly (Bun.write), NOT through the agent tool loop, so the read-only block can't block it; (d) the planner system prompt is re-anchored each plan turn and RESTORED (no cross-turn leak) on approve/cancel/exit; (e) council failure is fail-open (falls back to a plain planner turn); (f) abort (Esc) tears down the council controller; (g) non-plan-mode turns behave exactly as before. Report as a findings list (most severe first) with file:line and a concrete failure scenario for each; if a finding is a real defect, FIX it directly and re-run \`bun run check && bun run lint && bun test\` to confirm still green. If you find nothing real, say so. Report the final diff --stat and test status.`,
  { phase: 'Review', effort: 'high' },
)

return {
  session: sessionRes?.slice(0, 400),
  council: councilRes?.slice(0, 400),
  runtime: runtimeRes?.slice(0, 400),
  tui: tuiRes?.slice(0, 600),
  tests: testResults.map((t) => (t ?? '').slice(0, 300)),
  verifyGreen: green,
  review: review?.slice(0, 1200),
}

