export interface CouncilFinding { id: string; source: "researcher" | "critic" | "keeper"; summary: string; severity: "info" | "concern" | "blocker"; round: number; }
export interface PlanConstraint { id: string; text: string; source: "user" | "council"; }
export interface PlanFact { id: string; text: string; round: number; }
export interface SurfacedQuestion { question: string; header: string; options: { label: string; description?: string }[]; why: string; }
export interface CouncilRoundResult {
  draftDelta: string;
  decisions: { topic: string; decision: string; rationale: string }[];
  findings: { source: "researcher" | "critic" | "keeper"; summary: string; severity: "info" | "concern" | "blocker" }[];
  faults: { summary: string; severity: "info" | "concern" | "blocker" }[];
  questions: SurfacedQuestion[];
  facts: string[];
  constraints: string[];
  costUsd: number;
  aborted: boolean;
}
export interface PlanSession {
  goal: string; draft: string;
  decisions: PlanDecision[]; openQuestions: OpenQuestion[];
  findings: CouncilFinding[]; constraints: PlanConstraint[]; facts: PlanFact[];
  rounds: number; totalCouncilCostUsd: number; createdAt: number; updatedAt: number;
}
export class PlanSessionStore {
  constructor(goal: string);
  get session(): PlanSession;
  setGoal(goal: string): void;
  applyCouncilResult(r: CouncilRoundResult): void;   // merge+dedup by normalized topic/question/summary; bump rounds and totalCouncilCostUsd; MUST be fail-open (never throw)
  recordUserTurn(text: string): void;                // append a PlanFact
  answerQuestion(question: string, answer: string): void; // mark matching OpenQuestion answered; add a resolvedBy:"user" PlanDecision
  addSurfacedQuestions(qs: SurfacedQuestion[], round: number): void; // append as status:"open" OpenQuestions (dedup)
  snapshotBlock(): string;   // compact re-anchor projection: goal, resolved decisions, hard constraints, still-open questions, current draft
  toMarkdown(): string;      // the ground-truth doc (see format below)
  summary(): string;         // one-line status
  hasSubstance(): boolean;   // decisions.length>0 || draft.trim().length>0
}
export function buildPlannerSystemPrompt(base: string, store: PlanSessionStore): string; // base persona + store.snapshotBlock()

// ---- src/minima/plan_council.ts ----
export interface CouncilEvent { phase: "scope" | "research" | "keeper" | "critic" | "synth" | "done"; note: string; }
export interface CouncilOptions {
  parent: MinimaAgent;            // from ../minima/runtime.ts (import type)
  metaModel: Model;              // fixed cheap model for keeper/critic/synth complete() calls
  signal?: AbortSignal | null;
  workdir?: string;              // default process.cwd()
  maxResearchers?: number;       // default 3
  concurrency?: number;          // default 3
  maxCriticPasses?: number;      // default 3
  roundBudgetUsd?: number;       // soft cap; stop launching researchers once exceeded
  apiKey?: string;
  spawn?: SpawnFn;               // injectable for tests; DEFAULT = createSpawn({parent, workdir, onChildEvent})
  onEvent?: (e: CouncilEvent) => void;
  onChildEvent?: (e: ChildEvent) => void;
}
export class Critic {
  constructor(model: Model, opts?: { apiKey?: string; timeout?: number });
  attack(goal: string, approach: string, findings: string, signal?: AbortSignal | null): Promise<{ summary: string; severity: "info" | "concern" | "blocker" }[]>;
}
export function shouldConveneCouncil(userTurn: string): boolean; // adaptive cadence: return false for short acknowledgements/confirmations (e.g. <=~6 words, "yes"/"ok"/"do that"/"option b"), true for substantive turns
export function runCouncilRound(session: PlanSession, userTurn: string, opts: CouncilOptions): Promise<CouncilRoundResult>;
=== END CONTRACT ===

GROUND-TRUTH .md FORMAT (PlanSessionStore.toMarkdown): a single doc titled "# Ground Truth: <goal>" with a generated-by subtitle (N rounds, $cost), then sections: ## Goal, ## Constraints (bullet list), ## Key Decisions (### <topic> with **Decision:** / **Rationale:** / provenance "resolved by <who>, round N"), ## Plan (the draft prose), ## Open Questions (unresolved ones, flagged), ## Context & Findings (bulleted, tagged by source). Deterministic string assembly — no LLM call.
`

const DESIGN = `
BEHAVIORAL DESIGN (user-confirmed):
- Adaptive cadence: shouldConveneCouncil() decides whether a plan turn convenes the council.
- Standard depth: <=3 parallel read-only researchers + a keeper + 1 critic + a synth stage.
- Critic self-improve loop: inside runCouncilRound, after research, loop up to maxCriticPasses (default 3): critic.attack the current draftDelta; if it returns faults, do ONE meta "reviser" complete() call that revises the draftDelta to address them; re-attack; stop when no faults or the cap is hit. Then a synth complete() call turns findings+faults+userTurn into the CouncilRoundResult, RESOLVING trivial/self-answerable questions itself (as decisions/facts) and SURFACING only genuine decision-points as questions[] (cap ~2 per round).
- Council pipeline: (1) keeper deriveScopes = one complete() call -> up to maxResearchers non-overlapping {focus, boundaries, output_format, difficulty}; fallback to a single scope from userTurn if the call fails/parses empty. (2) research = build Delegation[] (focus->objective, boundaries verbatim, output_format, difficulty, effort:"light", tool_allowlist:["read","ls","glob","grep","web_search","web_fetch"], a small budget_usd slice) then executeDag(delegations, spawn, {depth:1, signal, concurrency}). (3) optional keeper post-check complete() flags off-scope findings (down-weight, don't discard). (4) critic self-improve loop. (5) synth.
- Meta calls (deriveScopes, keeper post-check, reviser, synth) and the Critic use complete() on the FIXED metaModel — they are deliberately OFF the routing/feedback loop (like LLMJudge), so they never corrupt routing propensities. Only researchers route (they go through child.promptRouted inside createSpawn). Do NOT re-rank or override any RoutingResult.
- Every meta complete() call must parse defensively (helper like completeJson that extracts the first JSON object/array and returns a safe fallback on any error) and pass through the abort signal.
- Cost: sum researcher ChildResult.costUsd into CouncilRoundResult.costUsd; respect roundBudgetUsd as a soft cap (stop launching researchers past it). On abort, return partial result with aborted:true.
`

