1	/**
2	 * PlanSessionStore — the in-memory single source of truth for a planning session.
3	 *
4	 * PURE: zero imports. The planning feature deliberately touches no database / persistence
5	 * layer — the session lives only for the duration of the /plan conversation and the ONLY
6	 * durable artifact is the ground-truth .md produced by toMarkdown() on /plan approve.
7	 *
8	 * The council appends structured deltas (decisions, findings, constraints, facts, surfaced
9	 * questions) each round; the store merges + dedups them and re-projects a compact snapshot
10	 * back into the planner's system prompt every turn. All mutation is fail-open.
11	 */
12	
13	const newId = (): string => crypto.randomUUID();
14	
15	const now = (): number => Date.now() / 1000;
16	
17	/** Whitespace-collapsed, lowercased key for dedup comparisons. */
18	const norm = (s: string): string => s.trim().replace(/\s+/g, " ").toLowerCase();
19	
20	const fmtUsd = (n: number): string => `$${(Number.isFinite(n) ? n : 0).toFixed(4)}`;
21	
22	export interface PlanDecision {
23	  id: string;
24	  topic: string;
25	  decision: string;
26	  rationale: string;
27	  resolvedBy: "council" | "user";
28	  round: number;
29	}
30	
31	export interface OpenQuestion {
32	  id: string;
33	  question: string;
34	  why: string;
35	  round: number;
36	  status: "open" | "answered" | "dropped";
37	  answer?: string;
38	}
39	
40	export interface CouncilFinding {
41	  id: string;
42	  source: "researcher" | "critic" | "keeper";
43	  summary: string;
44	  severity: "info" | "concern" | "blocker";
45	  round: number;
46	}
47	
48	export interface PlanConstraint {
49	  id: string;
50	  text: string;
51	  source: "user" | "council";
52	}
53	
54	export interface PlanFact {
55	  id: string;
56	  text: string;
57	  round: number;
